#include <bits/stdc++.h>
using namespace std;
const int N=1000005;
struct node
{
    int mod,pos;
    bool operator<(const node other) const 
    {
        if(mod==other.mod) return pos<other.pos;
        else return mod<other.mod;
    }
};
set<node> s[2];
int n,k;
long long ans;
string a,b;
int main()
{
    cin>>n>>k>>a>>b;
    a=" "+a;
    b=" "+b;
    for(int i=1;i<=n;i++)
    {
        if(a[i]==b[i]) continue;
        int t=a[i]-'0';
        if(s[!t].empty())
        {
            s[t].insert(node{i%k,i});
        }
        else
        {
            auto it=s[!t].lower_bound(node{i%k,0});
            if(it==s[!t].end())
            {
                it=s[!t].begin();
            }
            node t_node=*it;
            ans+=((i-t_node.pos-1)/k+1);
            s[!t].erase(it);
        }
    }
    cout<<ans;
    return 0;
}
